@app.route('/login', methods=['POST'])
def login():
    """Login endpoint with secure logging"""
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        app.logger.warning(f"Login attempt with missing credentials - request_id: {g.request_id}")
        return jsonify({'error': 'Missing credentials'}), 400
    
    username = data.get('username')
    password = data.get('password')
    
    # Validate input
    if not isinstance(username, str) or not isinstance(password, str):
        app.logger.warning(f"Login attempt with invalid data types - request_id: {g.request_id}")
        return jsonify({'error': 'Invalid credentials format'}), 400
    
    if len(username) > 100 or len(password) > 100:
        app.logger.warning(f"Login attempt with oversized credentials - request_id: {g.request_id}")
        return jsonify({'error': 'Invalid credentials'}), 400
    
    # Authenticate
    if authenticate_user(username, password):
        # Log successful login (username only, never password)
        app.logger.info(f"Successful login - username: {username}, request_id: {g.request_id}")
        
        # Generate secure token (example - use proper JWT or session management)
        token = hashlib.sha256(f"{username}{time.time()}".encode()).hexdigest()
        
        return jsonify({
            'message': 'Login successful',
            'token': token
        }), 200
    else:
        # Log failed login attempt (username only for security monitoring)
        app.logger.warning(f"Failed login attempt - username: {username}, request_id: {g.request_id}")
        return jsonify({'error': 'Invalid credentials'}), 401


